proof fn phi_1_lemma_pt_walk_external_body_completeness(mem: PTMem, va: usize)
    ensures
        mem.pt_walk(va).complete,
        0 < mem.pt_walk(va).path.len() <= 4,
{
    PTMem::lemma_pt_walk(mem, va);
}

proof fn phi_2_lemma_pt_walk_path_entries_match_reads(mem: PTMem, va: usize, i: int)
    requires
        0 <= i < mem.pt_walk(va).path.len(),
    ensures
        mem.pt_walk(va).path[i].1 == (PDE { entry: mem.read(mem.pt_walk(va).path[i].0), layer: Ghost(i as nat) })@,
{
    PTMem::lemma_pt_walk(mem, va);
}

proof fn phi_3_lemma_write_seq_domain_monotonic(mem: PTMem, writes: Seq<(usize, usize)>)
    ensures
        mem.mem.dom().subset_of(mem.write_seq(writes).mem.dom()),
{
    mem.lemma_write_seq(writes);
}

proof fn phi_4_lemma_pt_walk_no_directory_last(mem: PTMem, va: usize)
    ensures
        !(mem.pt_walk(va).path.last().1 is Directory),
{
    PTMem::lemma_pt_walk(mem, va);
}

proof fn phi_5_lemma_pt_walk_intermediate_present(mem: PTMem, va: usize, i: int)
    requires
        0 <= i < mem.pt_walk(va).path.len() - 1,
    ensures
        mem.pt_walk(va).path[i].1 is Directory,
        mem.read(mem.pt_walk(va).path[i].0) & 1 == 1,
{
    PTMem::lemma_pt_walk(mem, va);
}
